```cpp
// 提取骨架，并将骨架的像素位置存储在一个列表中
std::vector<cv::Point> skeletonPoints;
cv::findNonZero(skeleton, skeletonPoints);

// 将骨架点的坐标分离为 x 和 y
std::vector<double> xData, yData;
for (const cv::Point& point : skeletonPoints)
{
    xData.push_back(point.x);
    yData.push_back(point.y);
}

// 多项式拟合骨架点
int degree = 3; // 多项式的阶数
cv::Mat polyCoeffs;
cv::polyfit(xData, yData, degree, polyCoeffs);

// 生成拟合曲线上的点
std::vector<cv::Point> fittedCurve;
for (int x = 0; x < skeleton.cols; ++x)
{
    int y = 0;
    for (int i = 0; i < degree + 1; ++i)
    {
        y += polyCoeffs.at<double>(i) * std::pow(x, degree - i);
    }
    fittedCurve.push_back(cv::Point(x, y));
}
```

上述代码通过多项式拟合将骨架点拟合成了曲线，并生成了拟合曲线上的坐标点。请注意，这只是一个示例，使用多项式进行拟合。根据您的需求，您可能需要选择适当的曲线拟合方法和拟合阶数，并根据具体情况做出相应的调整和优化。
